import React, { useState } from 'react';
import { Copy, CheckCircle } from 'lucide-react';

const SitioWebInformativo = () => {
  const [copiedIndex, setCopiedIndex] = useState(null);

  const handleCopy = (text, index) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  return (
    <div className="bg-white p-8 max-w-4xl mx-auto">
      {/* Sección de Párrafos */}
      <div className="mb-8">
        <p className="text-lg text-gray-700 mb-4">
          Primer párrafo con información relevante sobre el tema principal del sitio web. 
          Aquí se introduce el contexto y se captura la atención del lector. 
          Se pueden incluir datos interesantes o estadísticas que generen interés. 
          La información debe ser clara y concisa para mantener la atención.
        </p>

        <p className="text-lg text-gray-700 mb-4">
          Segundo párrafo que profundiza en los detalles introducidos anteriormente. 
          Se explican conceptos más específicos relacionados con el tema principal. 
          Se pueden agregar ejemplos o casos de estudio que ilustren la información. 
          El objetivo es proporcionar más contexto y comprensión al lector.
        </p>
      </div>

      {/* Copy Box */}
      <div className="bg-gray-100 p-6 rounded-lg mb-8">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-xl font-semibold">Texto para Copiar</h3>
          <button 
            onClick={() => handleCopy('Tu texto aquí para copiar', 0)}
            className="text-gray-600 hover:text-blue-600"
          >
            {copiedIndex === 0 ? (
              <CheckCircle className="w-6 h-6 text-green-500" />
            ) : (
              <Copy className="w-6 h-6" />
            )}
          </button>
        </div>
        <pre className="bg-white p-4 rounded-md text-gray-800 overflow-x-auto">
          Tu texto aquí para copiar
        </pre>
      </div>

      {/* Párrafos Adicionales */}
      <div className="mb-8">
        <p className="text-lg text-gray-700 mb-4">
          Tercer párrafo que continúa desarrollando el tema principal. 
          Se pueden introducir nuevos aspectos o perspectivas relacionadas. 
          La información debe ser coherente con los párrafos anteriores. 
          Se busca mantener el interés del lector con contenido relevante.
        </p>

        <p className="text-lg text-gray-700 mb-4">
          Cuarto párrafo que concluye o resume los puntos principales. 
          Se pueden incluir reflexiones o conclusiones importantes. 
          Se destaca el valor o la relevancia de la información presentada. 
          El objetivo es dejar un impacto final en el lector.
        </p>
      </div>

      {/* Sección de Imagen */}
      <div className="mb-8">
        <img 
          src="/api/placeholder/800/400" 
          alt="Imagen Ilustrativa" 
          className="w-full rounded-lg shadow-md"
        />
        <p className="text-sm text-gray-600 mt-2 text-center">
          Descripción o pie de foto para la imagen
        </p>
      </div>
    </div>
  );
};

export default SitioWebInformativo;
